// Build context for AI email generation
const prospect = $input.first().json;

// Determine the hook angle based on pain points
let hookAngle = 'general';
let specificPain = '';

if (prospect.fields['Has Communication Pain']) {
  hookAngle = 'missed_calls';
  specificPain = 'I noticed some of your reviews mention customers having trouble reaching you';
} else if (prospect.fields['Pain Points']?.includes('response_time')) {
  hookAngle = 'slow_response';
  specificPain = 'I saw a few reviews mentioning wait times for callbacks';
} else if (prospect.fields['Google Rating'] < 4.0) {
  hookAngle = 'reputation';
  specificPain = 'I noticed you\'re at ' + prospect.fields['Google Rating'] + ' stars - there might be some quick wins to boost that';
} else {
  hookAngle = 'growth';
  specificPain = 'I saw you\'re doing well with ' + prospect.fields['Review Count'] + ' reviews';
}

// Get company name for personalization
const companyName = prospect.fields['Company Name'] || 'your company';
const firstName = prospect.fields['Owner First Name'] || 'there';
const city = prospect.fields['City'] || 'your area';

// Seasonal angle
const month = new Date().getMonth();
let seasonalHook = '';
if (month >= 4 && month <= 8) {
  seasonalHook = 'With summer in full swing, I know AC calls are probably flooding in';
} else if (month >= 9 && month <= 11) {
  seasonalHook = 'As we head into heating season, call volume is about to spike';
} else {
  seasonalHook = 'I know this time of year can be unpredictable for call volume';
}

return {
  json: {
    prospect: prospect,
    prospectId: prospect.id,
    companyName: companyName,
    firstName: firstName,
    city: city,
    hookAngle: hookAngle,
    specificPain: specificPain,
    seasonalHook: seasonalHook,
    email: prospect.fields['Verified Email'] || prospect.fields['Possible Emails']?.split(', ')[0],
    rating: prospect.fields['Google Rating'],
    reviewCount: prospect.fields['Review Count'],
    negativeReviews: prospect.fields['Negative Reviews'] || ''
  }
};

