// Parse and validate the AI-generated emails
const rawResponse = $input.first().json.message?.content || $input.first().json.text || '{}';
let emails;

try {
  emails = JSON.parse(rawResponse);
} catch (e) {
  // Try to extract JSON from the response
  const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    emails = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('Could not parse AI response');
  }
}

const context = $('Build Email Context').first().json;

return {
  json: {
    prospectId: context.prospectId,
    prospect: context.prospect,
    toEmail: context.email,
    companyName: context.companyName,

    // Email 1: Initial outreach
    email1: {
      subject: emails.subject,
      body: emails.body,
      sendAt: new Date().toISOString()
    },

    // Email 2: Follow-up (3 days later)
    email2: {
      subject: emails.followUp1Subject,
      body: emails.followUp1Body,
      sendAt: new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString()
    },

    // Email 3: Breakup (7 days after first)
    email3: {
      subject: emails.followUp2Subject,
      body: emails.followUp2Body,
      sendAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString()
    }
  }
};
